#include <bits/stdc++.h>
#define int unsigned long long
using namespace std;
int n , father[ 1000005 ];
int d[ 100005 ];
int siz[ 100005 ];
void init() {
	for( int i = 1 ; i <= n ; i++ ) {
		father[ i ] = i;
		d[ i ] = 0;
		siz[ i ] = 1;
	}
}
int fid( int x ) {
	if( x != father[ x ] ) {
	    int tmp = fid( father[ x ] );
	    d[ x ] += d[ father[ x ] ];
		father[ x ] = tmp;
	}
	return father[ x ];
}
void Union( int x , int y ) {
	int a = fid( x ) , b = fid( y );
	if( a != b ) {
		father[ a ] = b;
		d[ a ] = siz[ b ];
		siz[ b ] += siz[ a ];
	}
}
signed main() {
	cin >> n;
	init();
	for( int i = 1 ; i <= n ; i++ ) {
		char c;
		int x , y;
		cin >> c;
		if( c == 'M' ) {
			cin >> x >> y;
			Union( x , y );
		} else if( c == 'C' ) {
			cin >> x;
			fid( x );
			cout << d[ x ] << '\n';
		}
	}
	return 0;
}
